// Function to handle redirection and parse access token from URL fragment
function handleOAuthCallback() {
  if (window.location.hash.includes('#access_token=')) {
    const hashParams = new URLSearchParams(window.location.hash.substring(1));
    const accessToken = hashParams.get('access_token');
    
    if (accessToken) {
      // Store the access token in session storage
      sessionStorage.setItem('accessToken', accessToken);
      
      // Redirect to a default page or perform other actions
      window.location.href = '#/';
    } else {
      console.error('Failed to retrieve access token.');
    }
  }
}

// Function to make API calls using the stored access token
function fetchProtectedResource(url) {
  const accessToken = sessionStorage.getItem('accessToken');
  
  if (accessToken) {
    fetch(url, {
      headers: {
        'Authorization': `Bearer ${accessToken}`
      }
    })
    .then(response => response.json())
    .then(data => console.log(data))
    .catch(error => console.error('Error fetching data:', error));
  } else {
    console.error('Access token not found.');
  }
}

// Handle OAuth callback on page load
window.onload = handleOAuthCallback;

// Example API call
